package org.apache.commons.codec.binary;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.codec.binary.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.codec.binary.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.apache.commons.codec.binary.Base32;

public class StepDefs {

    private Base32 base32;
    private Exception exception;

    @Given("I wish to create a Base32 codec instance")
    public void i_wish_to_create_a_base32_codec_instance() {
        // Preparation for creating Base32 instance
    }

    @Given("I enable the {string} variant \\(Base32 Hex)")
    public void i_enable_the_hex_variant_base32_hex(String variant) {
        // Using hex variant means using the hex alphabet (0-9, A-V)
    }

    @Given("I select {char} as the padding byte")
    public void i_select_as_the_padding_byte(Character paddingChar) {
        // Store the padding character for later use
        try {
            base32 = new Base32(paddingChar);
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @When("I instantiate the Base32 codec with these parameters")
    public void i_instantiate_the_base32_codec_with_these_parameters() {
        // The instantiation happened in the Given step
    }

    @Then("the instantiation should complete successfully")
    public void the_instantiation_should_complete_successfully() {
        if (this.exception != null) {
            fail("Expected instantiation to succeed, but got exception: " + this.exception.getMessage());
        }
        assertNotNull("Base32 instance should not be null", base32);
    }

    @Then("no IllegalArgumentException should be thrown")
    public void no_illegal_argument_exception_should_be_thrown() {
        if (this.exception instanceof IllegalArgumentException) {
            fail("IllegalArgumentException was thrown: " + this.exception.getMessage());
        }
    }
}

